<?php require_once __DIR__.'/../app/bootstrap.php'; admin_header('ダッシュボード'); $d=db(); $stats=['登録RSS数'=>$d->query('SELECT COUNT(*) FROM feeds')->fetchColumn(),'取得記事数'=>$d->query('SELECT COUNT(*) FROM articles')->fetchColumn(),'最新投稿日時'=>$d->query('SELECT MAX(posted_at) FROM post_history')->fetchColumn()?:'-','最新投稿件数'=>$d->query('SELECT article_count FROM post_history ORDER BY id DESC LIMIT 1')->fetchColumn()?:0,'最終RSS取得結果'=>$d->query('SELECT last_result FROM feeds ORDER BY last_fetched_at DESC LIMIT 1')->fetchColumn()?:'-','Cron実行間隔'=>setting('cron_interval_minutes',60).'分','次回実行目安'=>'最終実行から'.setting('cron_interval_minutes',60).'分後','エラー件数'=>$d->query("SELECT COUNT(*) FROM logs WHERE level='error'")->fetchColumn()]; echo'<div class=stats>'; foreach($stats as $k=>$v) echo'<div class=stat><b>'.e($k).'</b><p>'.e($v).'</p></div>'; echo'</div>'; admin_footer();
